script:
// «Сплетник-дуо» — UI-журнал как ExtBlocks Script-блок (JS). Номер может быть про {{char}}, про {{user}} или про обоих.
// Читает <journalDuo>-блоки из message.extra.extblocks, копит стойкий архив в localStorage,
// рисует флип-виджет, инжектит мягкие эффекты, «новый номер» форсирует генерацию journalDuo.
// Субъект каждой рубрики берётся из data.subjects[рубрика] || data.subject ("char"/"user").
if (window.SJD && window.SJD.ready) {
    try { window.SJD.injectCSS && window.SJD.injectCSS(); window.SJD.refresh(); } catch (e) {}
} else {
    const ctx = (typeof context !== 'undefined' && context) ? context : SillyTavern.getContext();
    const runST = (typeof executeST === 'function') ? executeST : (s) => ctx.executeSlashCommandsWithOptions?.(s);
    const FX_KEY = 'SJD_ONESHOT';
    const ZOD = { 'Овен':'♈','Телец':'♉','Близнецы':'♊','Рак':'♋','Лев':'♌','Дева':'♍','Весы':'♎','Скорпион':'♏','Стрелец':'♐','Козерог':'♑','Водолей':'♒','Рыбы':'♓' };
    const SIGNS = Object.keys(ZOD);

    let issues = [], viewIndex = 0, pages = [], cur = 0, animating = false, busy = false, autoCounter = 0;
    let overlayEl, pagesEl, dotsEl, toastEl, fabEl;

    // ---------- helpers ----------
    const esc = (s) => String(s == null ? '' : s).replace(/[&<>"]/g, c => ({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;' }[c]));
    const zglyph = (s) => ZOD[String(s || '').trim()] || '✦';
    const gc = () => { try { return SillyTavern.getContext(); } catch (e) { return ctx; } };
    const curChar = () => { const c = gc(); return c.characterId == null ? null : (c.characters?.[c.characterId] || null); };
    const charKey = () => { const ch = curChar(); return ch ? (ch.avatar || ch.name) : 'none'; };
    function avatarUrl() {
        const av = curChar()?.avatar;
        if (!av || av === 'none') return null;
        try { const g = gc(); if (typeof g.getThumbnailUrl === 'function') return g.getThumbnailUrl('avatar', av); } catch (e) {}
        return '/thumbnail?type=avatar&file=' + encodeURIComponent(av);
    }
    // имена/аватар двух «звёзд»: персонаж и активная персона юзера
    const charName = () => curChar()?.name || 'персонаж';
    const userName = () => { const c = gc(); return (c && c.name1) ? String(c.name1) : 'ты'; };
    // ctx не отдаёт аватар персоны — берём из DOM (аватар последнего юзер-сообщения / шторка персон)
    function userAvatarUrl() {
        try {
            const msgs = document.querySelectorAll('#chat .mes[is_user="true"] .avatar img');
            const last = msgs[msgs.length - 1];
            if (last && last.src) return last.src;
            const sel = document.querySelector('#user_avatar_block .avatar-container.selected .avatar img, #user_avatar_block .avatar.selected img, #user_avatar_block .avatar img');
            if (sel && sel.src) return sel.src;
        } catch (e) {}
        return null;
    }
    const isUser = (subj) => subj === 'user';
    const subjName = (subj) => isUser(subj) ? userName() : charName();
    const otherName = (subj) => isUser(subj) ? charName() : userName();
    const subjAvatar = (subj) => isUser(subj) ? userAvatarUrl() : avatarUrl();
    function dLabel(d) { if (!d) return ''; const t = new Date(d); return isNaN(t) ? '' : t.toLocaleDateString('ru-RU', { month:'long', year:'numeric' }); }
    function dShort(d) { if (!d) return ''; const t = new Date(d); return isNaN(t) ? '' : t.toLocaleDateString('ru-RU', { day:'numeric', month:'short' }); }

    // мем для обложки через memegen.link (ИИ выбирает шаблон + пишет подпись)
    const MEME_TEMPLATES = ['drake', 'db', 'cmm', 'fry', 'success', 'doge', 'aliens', 'disastergirl', 'fine', 'gru', 'mordor', 'buzz'];
    function memeSeg(s) {
        s = String(s == null ? '' : s).trim();
        if (!s) return '_';
        return s
            .replace(/_/g, '__').replace(/-/g, '--').replace(/ /g, '_')
            .replace(/\?/g, '~q').replace(/&/g, '~a').replace(/%/g, '~p')
            .replace(/#/g, '~h').replace(/\//g, '~s').replace(/\\/g, '~b')
            .replace(/</g, '~l').replace(/>/g, '~g').replace(/"/g, "''").replace(/\n/g, '~n')
            .split('').map(c => c.charCodeAt(0) > 127 ? encodeURIComponent(c) : c).join('');
    }
    function memeUrl(m) {
        if (!m || !m.template) return null;
        const t = MEME_TEMPLATES.includes(m.template) ? m.template : 'fine';
        const top = memeSeg(m.top), bottom = memeSeg(m.bottom);
        if (top === '_' && bottom === '_') return null;
        return `https://api.memegen.link/images/${t}/${top}/${bottom}.png?font=notosans`;
    }

    // стабильный псевдо-рандом на номер: skin-раскладки не дёргаются при перелистывании
    function rngFrom(seed) { let s = (Math.floor(seed) * 2654435761) >>> 0 || 1; return () => { s = (s * 1664525 + 1013904223) >>> 0; return s / 4294967296; }; }
    function shuffleA(arr, rng) { arr = arr.slice(); for (let k = arr.length - 1; k > 0; k--) { const j = Math.floor(rng() * (k + 1)); const t = arr[k]; arr[k] = arr[j]; arr[j] = t; } return arr; }

    // settings (tone/auto/struct/decider — глобально; sign — на персонажа)
    // struct: 'mixed' (вперемешку) | 'solo' (целый номер про одного); decider: 'ai'|'alt'|'rand'|'char'|'user'
    const CFG_DEF = { tone:'tabloid', autoN:0, cover:'avatar', struct:'mixed', decider:'ai' };
    function loadCfg() { try { return Object.assign({}, CFG_DEF, JSON.parse(localStorage.getItem('sjd_cfg')) || {}); } catch (e) { return Object.assign({}, CFG_DEF); } }
    function saveCfg(c) { try { localStorage.setItem('sjd_cfg', JSON.stringify(c)); } catch (e) {} }
    function loadSign() { try { return localStorage.getItem('sjd_sign:' + charKey()) || ''; } catch (e) { return ''; } }
    function saveSign(v) { try { v ? localStorage.setItem('sjd_sign:' + charKey(), v) : localStorage.removeItem('sjd_sign:' + charKey()); } catch (e) {} }

    // стойкий архив в localStorage (на персонажа)
    function loadArchive() { try { return JSON.parse(localStorage.getItem('sjd_arch:' + charKey())) || []; } catch (e) { return []; } }
    function saveArchive(a) { try { localStorage.setItem('sjd_arch:' + charKey(), JSON.stringify(a.slice(0, 40))); } catch (e) {} }
    const sigOf = (d) => `${d.horoscope || ''}|${d.rumor || ''}|${d.bestof || ''}`.slice(0, 200);

    function extractJson(s) {
        if (!s) return null;
        s = String(s).replace(/```json/gi, '').replace(/```/g, '');
        const a = s.indexOf('{'), b = s.lastIndexOf('}');
        if (a < 0 || b < 0 || b < a) return null;
        const frag = s.slice(a, b + 1);
        try { return JSON.parse(frag); } catch (e) {}
        try { return JSON.parse(frag.replace(/,\s*([}\]])/g, '$1')); } catch (e) {}
        return null;
    }
    // допустимые субъект-рубрики (compat всегда про пару {{char}}×{{user}}, в subjects не нужен)
    const SUBJ_RUBRIC_KEYS = ['horoscope','prediction','rumor','scandal','diary','society','letters','interview','top5','fashion','badadvice','bestof','ad'];
    function sanitizeSubjects(o) {
        const out = {};
        if (o && typeof o === 'object') for (const k of SUBJ_RUBRIC_KEYS) { const v = o[k]; if (v === 'char' || v === 'user') out[k] = v; }
        return out;
    }
    function normIssue(d) {
        if (!d || typeof d !== 'object') return null;
        const ci = (v, a, b, def) => { v = parseInt(v); return isFinite(v) ? Math.max(a, Math.min(b, v)) : def; };
        const s = (v, n) => String(v == null ? '' : v).slice(0, n);
        // мягкая обрезка прозы: режем по границе слова + многоточие, чтобы не рвать на полуслове
        const clip = (v, n) => {
            v = String(v == null ? '' : v).trim();
            if (v.length <= n) return v;
            let cut = v.slice(0, n);
            const sp = cut.lastIndexOf(' ');
            if (sp > n * 0.6) cut = cut.slice(0, sp);
            return cut.replace(/[\s.,;:!?…«»"'(\-—]+$/, '') + '…';
        };
        return {
            subject: (d.subject === 'user') ? 'user' : 'char',
            subjects: sanitizeSubjects(d.subjects),
            sign: s(d.sign, 20), stars: ci(d.stars, 1, 5, 3), horoscope: clip(d.horoscope, 600), mood: clip(d.mood, 220),
            horo_love: clip(d.horo_love, 200), horo_money: clip(d.horo_money, 200), horo_warning: clip(d.horo_warning, 200), lucky: clip(d.lucky, 100),
            prediction: clip(d.prediction, 440), prediction_fx: clip(d.prediction_fx, 220),
            compat_percent: ci(d.compat_percent, 1, 100, 72), compat_verdict: s(d.compat_verdict, 60) || 'Есть искра',
            compat_passion: ci(d.compat_passion, 1, 100, 60), compat_drama: ci(d.compat_drama, 1, 100, 40), compat_note: clip(d.compat_note, 480),
            rumor: clip(d.rumor, 520), rumor_source: clip(d.rumor_source, 280), scandal: clip(d.scandal, 520), scandal_denial: clip(d.scandal_denial, 280),
            diary: clip(d.diary, 520), diary_mood: clip(d.diary_mood, 220),
            bestof: clip(d.bestof, 440), bestof_caption: clip(d.bestof_caption, 240), ad: clip(d.ad, 220),
            letters: (d.letters && typeof d.letters === 'object' && (d.letters.q || d.letters.a)) ? { q: clip(d.letters.q, 320), a: clip(d.letters.a, 440) } : null,
            fashion: (d.fashion && typeof d.fashion === 'object' && d.fashion.look) ? { look: clip(d.fashion.look, 320), verdict: s(d.fashion.verdict, 70), score: ci(d.fashion.score, 1, 100, 66) } : null,
            top5: (d.top5 && typeof d.top5 === 'object' && Array.isArray(d.top5.items) && d.top5.items.filter(Boolean).length >= 2) ? { title: clip(d.top5.title, 100), items: d.top5.items.slice(0, 5).map(x => clip(x, 160)).filter(Boolean) } : null,
            interview: Array.isArray(d.interview) ? d.interview.slice(0, 3).map(x => ({ q: clip(x && x.q, 200), a: clip(x && x.a, 360) })).filter(x => x.q || x.a) : [],
            badadvice: clip(d.badadvice, 320), society: clip(d.society, 480),
            headlines: Array.isArray(d.headlines) ? d.headlines.slice(0, 3).map(h => clip(h, 100)) : [],
            gift: (d.gift && typeof d.gift === 'object') ? { name: s(d.gift.name, 60) || 'подарок', mood: clip(d.gift.mood, 180) } : null,
            meme: (d.meme && typeof d.meme === 'object') ? { template: s(d.meme.template, 24), top: s(d.meme.top, 80), bottom: s(d.meme.bottom, 80) } : null,
        };
    }
    // свежие выпуски из чата (новейшие первыми)
    function collectFromChat() {
        const chat = gc().chat || [];
        const out = [];
        for (let i = 0; i < chat.length; i++) {
            const ext = chat[i] && chat[i].extra && chat[i].extra.extblocks;
            if (!ext) continue;
            const m = /<journalDuo>([\s\S]*?)<\/journalDuo>/i.exec(ext);
            if (!m) continue;
            const data = normIssue(extractJson(m[1]));
            if (data) out.push({ data, date: chat[i].send_date });
        }
        out.reverse();
        return out;
    }
    const currentIssue = () => issues[Math.min(viewIndex, Math.max(0, issues.length - 1))] || null;

    // ---------- мягкие эффекты «на одно сообщение» (несколько слотов) ----------
    const pendingKeys = new Set();
    function armOneShot(key, text) {
        try {
            const t = ctx.substituteParams ? ctx.substituteParams(text) : text;
            ctx.setExtensionPrompt(key, t, 1 /* IN_CHAT */, 0, false, 0 /* SYSTEM */);
            pendingKeys.add(key);
        } catch (e) { console.error('[SJD] inject', e); }
    }
    const applyOneShot = (text) => armOneShot(FX_KEY, text);
    function clearOneShots() { pendingKeys.forEach(k => { try { ctx.setExtensionPrompt(k, ''); } catch (e) {} }); pendingKeys.clear(); }

    // ---------- рендер ----------
    const stars = (n) => { n = Math.max(0, Math.min(5, n | 0)); let h = ''; for (let i = 0; i < 5; i++) h += `<i class="fa-solid fa-star"${i >= n ? ' style="opacity:.25"' : ''}></i>`; return h; };

    function render() {
        if (!pagesEl) return;
        const name = curChar()?.name || 'персонаж';
        const av = avatarUrl();
        const avStyle = av ? ` style="background-image:url('${av}')"` : '';
        const it = currentIssue();

        if (!it) {
            pagesEl.innerHTML = `<section class="sjd-page sjd-cover active">
                <div class="sjd-issue">черновик</div>
                <div class="sjd-mast">Сплетник</div><div class="sjd-sub">про ${esc(charName())} и ${esc(userName())}</div>
                <div class="sjd-avatar"${avStyle}>${av ? '' : '<i class="fa-solid fa-user"></i>'}<div class="cap">${esc(name)}</div></div>
                <div class="sjd-empty"><p class="sjd-body">Свежего номера ещё нет.</p>
                    <button class="sjd-btn" data-new><i class="fa-solid fa-rotate"></i> Выпустить номер</button></div>
            </section>`;
            setupAfterRender(); setTitle();
            return;
        }
        const i = it.data;
        // субъект рубрики: data.subjects[рубрика] → fallback на субъект всего номера ("char"/"user")
        const subjOf = (t) => (i.subjects && (i.subjects[t] === 'user' || i.subjects[t] === 'char')) ? i.subjects[t] : (i.subject === 'user' ? 'user' : 'char');
        const SUBJ_RUBRICS = new Set(SUBJ_RUBRIC_KEYS);
        const presentSubj = new Set();
        // чип «про кого» вверху рубрики (compat — всегда пара двоих)
        const whoChip = (t) => {
            if (t === 'compat') return `<div class="sjd-who"><i class="fa-solid fa-heart"></i> ${esc(charName())} × ${esc(userName())}</div>`;
            if (!SUBJ_RUBRICS.has(t)) return '';
            const sj = subjOf(t); presentSubj.add(sj);
            return `<div class="sjd-who"><i class="fa-solid fa-user-tag"></i> про ${esc(subjName(sj))}</div>`;
        };
        const horoSubj = subjOf('horoscope');
        // ручной знак из настроек — только для гороскопа ПРО ПЕРСОНАЖА; для юзера знак выбирает ИИ
        const signDisplay = (horoSubj === 'char' ? (loadSign() || i.sign) : i.sign);

        // стабильная на номер раскладка: skin страниц тасуется от seed=номер (не дёргается при листании)
        const rng = rngFrom(it.num || 1);
        const skinBag = shuffleA(['', 'sjd-l-bold', 'sjd-l-stamp', 'sjd-l-mag', 'sjd-l-accent'], rng);
        let skinI = 0;
        const nextSkin = () => skinBag[(skinI++) % skinBag.length];
        const head = (k, t) => `<div class="sjd-kicker">${esc(k)}</div><div class="sjd-title">${esc(t)}</div><div class="sjd-rule"></div>`;
        const inner = []; const idxOf = {};
        const add = (type, html, extra) => { idxOf[type] = inner.length + 1; inner.push(`<section class="sjd-page ${nextSkin()}${extra ? ' ' + extra : ''}">${whoChip(type)}${html}</section>`); };

        add('horoscope', head('звёзды на сегодня', 'Гороскоп · ' + (signDisplay || '')) + `
            <div class="sjd-zodiac">${zglyph(signDisplay)}</div><div class="sjd-stars">${stars(i.stars)}</div>
            <p class="sjd-body">${esc(i.horoscope)}</p>
            <div class="sjd-subgrid">
                ${i.horo_love ? `<div class="sjd-subitem"><i class="fa-solid fa-heart"></i><span>${esc(i.horo_love)}</span></div>` : ''}
                ${i.horo_money ? `<div class="sjd-subitem"><i class="fa-solid fa-sack-dollar"></i><span>${esc(i.horo_money)}</span></div>` : ''}
                ${i.horo_warning ? `<div class="sjd-subitem"><i class="fa-solid fa-triangle-exclamation"></i><span>${esc(i.horo_warning)}</span></div>` : ''}
            </div>
            ${i.lucky ? `<div class="sjd-lucky"><i class="fa-solid fa-clover"></i> ${esc(i.lucky)}</div>` : ''}
            <div class="sjd-center" style="margin-top:16px">${fxBtn(it.used, 'mood', 'fa-solid fa-wand-magic-sparkles', 'применить настроение', false, horoSubj)}</div>`);

        if (i.prediction) add('prediction', head('карты говорят', 'Предсказание дня') + `
            <div class="sjd-zodiac"><i class="fa-solid fa-wand-magic-sparkles"></i></div>
            <p class="sjd-body">${esc(i.prediction)}</p>
            <div class="sjd-center" style="margin-top:18px">${fxBtn(it.used, 'prediction', 'fa-solid fa-hand-sparkles', 'применить предчувствие', false, subjOf('prediction'))}</div>`);

        add('compat', head('только для двоих', 'Тест на совместимость') + `
            <div class="sjd-compat"><i class="fa-solid fa-heart sjd-heart-i"></i>
                <div class="sjd-big">${i.compat_percent | 0}<span>%</span></div>
                <div class="sjd-verdict">«${esc(i.compat_verdict)}»</div></div>
            <div class="sjd-bars">
                <div class="sjd-bar"><span>страсть</span><div class="sjd-bk"><i style="width:${Math.max(3, Math.min(100, i.compat_passion | 0))}%"></i></div><b>${i.compat_passion | 0}%</b></div>
                <div class="sjd-bar"><span>драма</span><div class="sjd-bk"><i style="width:${Math.max(3, Math.min(100, i.compat_drama | 0))}%"></i></div><b>${i.compat_drama | 0}%</b></div>
            </div>
            ${i.compat_note ? `<p class="sjd-body" style="margin-top:14px">${esc(i.compat_note)}</p>` : ''}`);

        add('rumor', head('по секрету всему свету', 'Слухи недели') + `
            <div class="sjd-gossip"><i class="fa-solid fa-quote-left sjd-qi"></i><p class="sjd-body">${esc(i.rumor)}</p>
                ${i.rumor_source ? `<div class="sjd-source">— ${esc(i.rumor_source)}</div>` : ''}</div>
            <div class="sjd-center" style="margin-top:18px">${fxBtn(it.used, 'rumor', 'fa-solid fa-bullhorn', 'поднять в чате', true, subjOf('rumor'))}</div>`);

        if (i.scandal) add('scandal', head('шок и трепет', 'Скандал недели') + `
            <div class="sjd-gossip sjd-scandal"><i class="fa-solid fa-triangle-exclamation sjd-qi"></i><p class="sjd-body">${esc(i.scandal)}</p></div>
            ${i.scandal_denial ? `<div class="sjd-denial"><i class="fa-solid fa-comment-slash"></i><span>${esc(subjName(subjOf('scandal')))} отрицает: «${esc(i.scandal_denial)}»</span></div>` : ''}
            <div class="sjd-center" style="margin-top:16px">${fxBtn(it.used, 'scandal', 'fa-solid fa-fire', 'вынести в чат', true, subjOf('scandal'))}</div>`);

        if (i.diary) add('diary', head('личное', 'Дневник') + `
            <div class="sjd-diary"><i class="fa-solid fa-feather-pointed sjd-qi"></i><p class="sjd-body" style="font-style:italic">${esc(i.diary)}</p></div>
            ${i.diary_mood ? `<div class="sjd-center" style="margin-top:18px">${fxBtn(it.used, 'diary', 'fa-solid fa-heart', 'проникнуться', true, subjOf('diary'))}</div>` : ''}`);

        if (i.society) add('society', head('кто с кем и где', 'Светская хроника') + `<p class="sjd-society">${esc(i.society)}</p>`);

        if (i.letters) add('letters', head('почта редакции', 'Письма читателей') + `<div class="sjd-letters">
            ${i.letters.q ? `<div class="sjd-letter-q"><span class="sjd-letter-lbl">читатель пишет</span>${esc(i.letters.q)}</div>` : ''}
            ${i.letters.a ? `<div class="sjd-letter-a"><span class="sjd-letter-lbl">${esc(subjName(subjOf('letters')))} отвечает</span>${esc(i.letters.a)}</div>` : ''}
        </div>`);

        if (i.interview && i.interview.length) add('interview', head('разговор по душам', 'Эксклюзив-интервью') + `<div class="sjd-interview">
            ${i.interview.map(p => `${p.q ? `<div class="sjd-iq">${esc(p.q)}</div>` : ''}${p.a ? `<div class="sjd-ia">${esc(p.a)}</div>` : ''}`).join('')}
        </div>`);

        if (i.top5) add('top5', head('хит-парад номера', i.top5.title || 'Горячая пятёрка') + `<div class="sjd-top5">
            ${i.top5.items.map((x, k) => `<div class="row"><div class="nrank">${k + 1}</div><div class="rtext">${esc(x)}</div></div>`).join('')}
        </div>`);

        if (i.fashion) add('fashion', head('от наших стилистов', 'Модный приговор') + `<div class="sjd-fashion">
            <p class="look">${esc(i.fashion.look)}</p>
            <div class="score">${i.fashion.score | 0}<span>/100</span></div>
            ${i.fashion.verdict ? `<div class="fverdict">«${esc(i.fashion.verdict)}»</div>` : ''}
        </div>`);

        if (i.badadvice) add('badadvice', head('наоборот', 'Вредный совет недели') + `<div class="sjd-badadvice"><i class="fa-solid fa-skull-crossbones"></i><p>${esc(i.badadvice)}</p></div>`);

        add('bestof', head('цитата месяца', 'Момент месяца') + `
            <i class="fa-solid fa-quote-left sjd-qi" style="font-size:24px"></i>
            <blockquote>${esc(i.bestof)}</blockquote>
            ${i.bestof_caption ? `<div class="sjd-cap" style="text-align:left;margin-top:14px">${esc(i.bestof_caption)}</div>` : ''}`, 'sjd-bestof');

        add('ad', head('по заявкам читателей', 'Реклама') + `
            <div class="sjd-adbtn" data-comic title="Прислать комикс в следующее сообщение">
                <i class="fa-solid fa-clapperboard"></i>
                <div class="sjd-adtext">${esc(i.ad || 'СЕНСАЦИЯ! Закажи комикс про свои лучшие моменты — прямо в чат!')}</div>
