    function showInstant(i) { if (i < 0 || i >= pages.length) return; pages[cur]?.classList.remove('active'); cur = i; pages[cur]?.classList.add('active'); updateNav(); }
    function goPage(i) { if (i === cur || i < 0 || i >= pages.length) return; if (Math.abs(i - cur) === 1) flip(i - cur); else showInstant(i); }
    function flip(dir) {
