        out.style.zIndex = 3; inc.classList.add('active'); inc.style.zIndex = 1;
        out.style.transition = 'transform .26s ease-in'; out.style.transform = 'rotateY(' + (dir > 0 ? -88 : 88) + 'deg)';
        setTimeout(() => {
            out.classList.remove('active'); out.style.transition = 'none'; out.style.transform = ''; out.style.zIndex = '';
            inc.style.zIndex = 3; inc.style.transition = 'none'; inc.style.transform = 'rotateY(' + (dir > 0 ? 90 : -90) + 'deg)';
            void inc.offsetWidth;
            inc.style.transition = 'transform .3s ease-out'; inc.style.transform = 'rotateY(0deg)';
            setTimeout(() => { inc.style.transition = ''; inc.style.transform = ''; inc.style.zIndex = ''; cur = t; animating = false; updateNav(); }, 305);
        }, 260);
    }
    function bounce() { const p = pages[cur]; if (!p) return; p.style.transition = 'transform .12s'; p.style.transform = 'translateX(5px)'; setTimeout(() => p.style.transform = 'translateX(-4px)', 120); setTimeout(() => { p.style.transform = ''; setTimeout(() => p.style.transition = '', 120); }, 240); }

    // ---------- действия ----------
    // один эффект на выпуск: после выбора остальные блокируются (it.used хранится в архиве)
    const FX_TOAST = { mood: 'настроение · 1 сообщение', prediction: 'предчувствие · 1 сообщение', diary: 'настроение · 1 сообщение', rumor: 'слух заброшен · 1 сообщение', scandal: 'скандал вынесен · 1 сообщение', gift: 'подарок · 1 сообщение' };
    const FX_RUBRIC = { mood: 'horoscope', prediction: 'prediction', diary: 'diary', rumor: 'rumor', scandal: 'scandal', gift: 'ad' };
    function applyEffect(k, subj) {
        const it = currentIssue(); if (!it || it.used) return; const i = it.data;
        // субъект эффекта: из кнопки (data-subj) или по рубрике эффекта
        if (subj !== 'char' && subj !== 'user') subj = (i.subjects && i.subjects[FX_RUBRIC[k]]) || i.subject || 'char';
        const P = subjName(subj), O = otherName(subj), uo = isUser(subj);
        if (k === 'mood') applyOneShot(`[Настроение сцены: сейчас ${P} ${i.mood || i.horoscope}]`);
        else if (k === 'prediction') applyOneShot(`[Предчувствие сцены (про ${P}): ${i.prediction_fx || i.prediction}]`);
        else if (k === 'diary') applyOneShot(`[Настроение сцены: ${P} ${i.diary_mood || 'задумчив(а)'}]`);
        else if (k === 'rumor') applyOneShot(uo
            ? `[Слух: про ${P} судачат — «${i.rumor}». ${O} в курсе этого слуха про ${P} и обыгрывает его в сцене.]`
            : `[Слух: о ${P} поговаривают — «${i.rumor}». ${P} только что услышал(а) об этом и реагирует.]`);
        else if (k === 'scandal') applyOneShot(uo
