            : `[Скандал: про ${P} всплыло — «${i.scandal}». ${P} в курсе шумихи и реагирует.]`);
        else if (k === 'gift') { const g = i.gift; if (!g) return; applyOneShot(`[Настроение сцены: ${P} под впечатлением — ${g.mood || g.name}]`); }
        else return;
        it.used = k; saveArchive(issues);
        reflectLock();
        toast(FX_TOAST[k] || 'эффект · 1 сообщение');
