    function reflectLock() {
        const used = currentIssue()?.used; if (!used) return;
        pagesEl.querySelectorAll('[data-apply]').forEach(b => {
            const k = b.dataset.apply; b.removeAttribute('data-apply'); b.disabled = true;
            if (k === used) { b.classList.add('done'); b.innerHTML = '<i class="fa-solid fa-check"></i> применено'; }
            else { b.classList.add('locked'); b.innerHTML = '<i class="fa-solid fa-lock"></i> уже выбран'; }
