    function armComic() {
        const i = currentIssue()?.data;
        const subj = i ? ((i.subjects && i.subjects.ad) || i.subject || 'char') : 'char';
        const name = subjName(subj) || 'герой';
        const clean = (s) => String(s || '').replace(/["'«»\\<>\n\r]/g, ' ').replace(/\s+/g, ' ').trim();
        const moment = clean(i?.bestof || (i?.headlines && i.headlines[0]) || 'последние бурные события').slice(0, 220);
        const imgPrompt = clean('funny retro 2000s tabloid comic strip, 3 chaotic panels recapping the best moments of ' + name + ', exaggerated chibi reactions, bold halftone screentone, Russian comic speech bubbles, lighthearted meme energy, about: ' + moment).slice(0, 520);
        const tag = `<img data-iig-instruction='{"prompt":"${imgPrompt}","aspect_ratio":"3:4","image_size":"1K"}' src="[IMG:GEN]">`;
        const ooc = `[OOC: Вне сюжета и без комментариев. В самом КОНЦЕ следующего ответа добавь отдельной строкой РОВНО это, ничего не меняя:\n${tag}\nЭто шуточная комикс-врезка про лучшие моменты.]`;
