    // вычисляет директиву «про кого / структура» для следующего номера по настройкам
    function subjectDirective(cfg) {
        const struct = cfg.struct || 'mixed', decider = cfg.decider || 'ai';
        const cn = charName(), un = userName();
        const last = (issues[0] && issues[0].data) ? issues[0].data.subject : null;
        const flip = (s) => s === 'char' ? 'user' : 'char';
        const coin = () => Math.random() < 0.5 ? 'char' : 'user';
        const persp = (s) => s === 'user' ? ('читателя ' + un) : ('персонажа ' + cn);
        if (struct === 'solo') {
            let subj;
            if (decider === 'char') subj = 'char';
            else if (decider === 'user') subj = 'user';
            else if (decider === 'rand') subj = coin();
            else subj = last ? flip(last) : coin(); // alt и ai: чередуем от прошлого, без перекоса
            let d = 'СТРУКТУРА: СОЛО-НОМЕР — ВЕСЬ выпуск целиком про ' + persp(subj) + '. Сделай subject=«' + subj + '», и для КАЖДОЙ заполненной рубрики subjects[рубрика]=«' + subj + '». Рубрика compat остаётся про пару ' + cn + '×' + un + '.';
            if (decider === 'ai') d += ' (Про кого делать — решай сам, но без перекоса к одному и тому же из номера в номер.)';
            return d;
        }
        let lean;
        if (decider === 'char') lean = 'сделай УПОР на персонажа ' + cn + ': большинство рубрик про него, пару рубрик — про ' + un + '.';
        else if (decider === 'user') lean = 'сделай УПОР на читателя ' + un + ': большинство рубрик про него, пару рубрик — про ' + cn + '.';
        else if (decider === 'alt') lean = 'лёгкий перекос в сторону ' + persp(last ? flip(last) : coin()) + ', но обязательно есть рубрики и про второго.';
        else if (decider === 'rand') lean = 'распредели рубрики между ними в произвольной пропорции (можно с перекосом в любую сторону).';
        else lean = 'раздели рубрики между персонажем ' + cn + ' и читателем ' + un + ' ПРИМЕРНО ПОРОВНУ, без перекоса; сам реши, что про кого.';
        return 'СТРУКТУРА: СМЕШАННЫЙ номер — ' + lean + ' Для КАЖДОЙ заполненной рубрики ОБЯЗАТЕЛЬНО проставь subjects[рубрика]=«char» или «user». subject = тот, про кого обложка (выбери сам). Рубрика compat — всегда про пару ' + cn + '×' + un + '.';
    }
    function buildHint() {
        const sign = loadSign(), cfg = loadCfg(), h = [];
        h.push(subjectDirective(cfg));
        if (sign) h.push('Знак зодиака персонажа ' + charName() + ' — ' + sign + ' (используй его для гороскопа ПРО ПЕРСОНАЖА).');
        if (cfg.tone === 'spicy') h.push('Тон максимально едкий и саркастичный, не жалей шпилек.');
        else if (cfg.tone === 'glamour') h.push('Тон гламурно-глянцевый, восторженный.');
        else if (cfg.tone === 'vanilla') h.push('Тон мягкий, тёплый, уютный.');
        // разнообразие мем-обложек: модель не помнит прошлые номера — подсказываем недавние шаблоны и просим взять другой
        const usedMemes = [...new Set(issues.slice(0, 3).map(it => it && it.data && it.data.meme && it.data.meme.template).filter(t => MEME_TEMPLATES.includes(t)))];
        if (usedMemes.length) {
            const fresh = MEME_TEMPLATES.filter(t => !usedMemes.includes(t));
            for (let i = fresh.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [fresh[i], fresh[j]] = [fresh[j], fresh[i]]; }
            h.push('Мем на обложке в прошлых номерах уже был на шаблонах: ' + usedMemes.join(', ') + '. НЕ бери их снова — выбери ДРУГОЙ шаблон, например из: ' + fresh.slice(0, 5).join(', ') + '. Меняй мем-шаблон от номера к номеру.');
        }
        // ротация доп-рубрик: что было в последних номерах — просим сделать упор на другие
        const OPT_RUBRICS = ['letters', 'fashion', 'top5', 'interview', 'badadvice', 'society'];
        const hadRubric = (d, r) => { if (!d) return false; const v = d[r]; return Array.isArray(v) ? v.length > 0 : !!v; };
        const recentRubrics = [...new Set([].concat(...issues.slice(0, 2).map(it => OPT_RUBRICS.filter(r => hadRubric(it.data, r)))))];
        if (recentRubrics.length) h.push('Доп-рубрики в прошлых номерах: ' + recentRubrics.join(', ') + '. В этот раз сделай упор на ДРУГИЕ доп-рубрики, чтобы номер отличался.');
        // разный объём номера → разное число страниц от выпуска к выпуску
        const SIZES = [
            'Объём номера: КОМПАКТНЫЙ — всего 1-2 доп-рубрики, и можешь опустить предсказание, скандал или дневник (оставь их пустыми). Тонкий выпуск.',
            'Объём номера: средний — 2 доп-рубрики.',
            'Объём номера: средний — 3 доп-рубрики.',
            'Объём номера: НАСЫЩЕННЫЙ — 4-5 разных доп-рубрик, и не забудь предсказание, скандал и дневник. Толстый выпуск.',
        ];
        h.push(SIZES[Math.floor(Math.random() * SIZES.length)]);
        // разный «голос» номера, чтобы не было одного шаблона на слова и шутки
        const ANGLES = [
            'Особый упор этого номера — абсурдный сюрреалистичный юмор и дикие бытовые детали.',
            'Этот номер — про утечки и псевдо-инсайдеров: побольше «нам шепнул источник» и интриги.',
            'В этом номере редакция ломает четвёртую стену и стебёт сама себя.',
            'Этот номер — гипертрофированный гламур, придыхание и пафос.',
            'Этот номер — холодный желчный сарказм и тонкие шпильки.',
            'Этот номер — конспирология и теории заговора вокруг звезды.',
        ];
        h.push(ANGLES[Math.floor(Math.random() * ANGLES.length)]);
        h.push('Не повторяй дословно заголовки, обороты и шутки из прошлых номеров — пиши свежими словами.');
        return h.join(' ').replace(/["\\]/g, '');
    }
