.sjd-panel{position:absolute;top:6px;right:6px;width:252px;max-height:88%;overflow:auto;background:var(--sjd-paper);border:1px solid var(--sjd-line);border-radius:10px;padding:10px;z-index:11;box-shadow:0 10px 24px rgba(40,34,30,.25);font:400 12.5px var(--sjd-sans);color:var(--sjd-ink);}
