.sjd-arow span{color:var(--sjd-ink2);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1;}
.sjd-arch-badge{position:absolute;top:24px;left:22px;font:600 8px var(--sjd-sans);letter-spacing:1.5px;text-transform:uppercase;color:#fff;background:var(--sjd-sand);padding:3px 7px;border-radius:10px;}
.sjd-srow{display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:10px;}
.sjd-srow:last-child{margin-bottom:0;}
