.sjd-shint{font:400 10px var(--sjd-sans);color:var(--sjd-ink2);text-align:center;margin-top:2px;}
.sjd-spin{animation:sjd-spin 1s linear infinite;}
@keyframes sjd-spin{to{transform:rotate(360deg)}}
/* ---- варьируемые макеты страниц (skin привязан к номеру) ---- */
.sjd-l-bold{border-top:5px solid var(--sjd-accent);}
