.sjd-fashion .look{font:400 13.5px/1.6 var(--sjd-sans);color:#5e574f;margin:0 0 14px;}
.sjd-fashion .score{font:300 52px/1 var(--sjd-serif);color:var(--sjd-accent-deep);}
.sjd-fashion .score span{font-size:20px;color:var(--sjd-ink2);}
.sjd-fashion .fverdict{font:italic 400 16px var(--sjd-serif);color:var(--sjd-ink);margin-top:8px;}
.sjd-top5{display:flex;flex-direction:column;margin-top:4px;}
