  .sjd-wrap{display:flex;flex-direction:column;width:min(362px,calc(100vw - 16px));height:calc(100vh - 16px);height:calc(100dvh - 16px - env(safe-area-inset-top,0px) - env(safe-area-inset-bottom,0px));max-height:calc(100dvh - 16px - env(safe-area-inset-top,0px) - env(safe-area-inset-bottom,0px));}
  .sjd-topbar{position:static;top:auto;height:34px;min-height:34px;margin:0 0 6px;flex:0 0 auto;}
  .sjd-magazine{width:100%;height:auto;flex:1 1 auto;min-height:0;}
  #sjd-fab{right:16px;bottom:calc(92px + env(safe-area-inset-bottom,0px));width:50px;height:50px;font-size:19px;}
}`;
        let st = document.getElementById('sjd-style');
        if (!st) { st = document.createElement('style'); st.id = 'sjd-style'; document.head.appendChild(st); }
        if (st.textContent !== css) st.textContent = css;
    }

    function buildUI() {
        injectCSS();
        if (document.getElementById('sjd-overlay')) { overlayEl = document.getElementById('sjd-overlay'); fabEl = document.getElementById('sjd-fab'); pagesEl = overlayEl.querySelector('.sjd-pages'); dotsEl = overlayEl.querySelector('.sjd-dots'); toastEl = overlayEl.querySelector('.sjd-toast'); return; }

        fabEl = document.createElement('div'); fabEl.id = 'sjd-fab'; fabEl.title = 'Сплетник';
        fabEl.innerHTML = '<i class="fa-solid fa-book-open"></i>';
        document.body.appendChild(fabEl);

        const signOpts = '<option value="">авто</option>' + SIGNS.map(s => `<option value="${s}">${s}</option>`).join('');
        overlayEl = document.createElement('div'); overlayEl.id = 'sjd-overlay';
        overlayEl.innerHTML = `<div class="sjd-wrap">
            <div class="sjd-topbar"><div class="sjd-ttl">Сплетник</div>
                <button class="sjd-icobtn sjd-new" title="Новый номер"><i class="fa-solid fa-rotate"></i></button>
                <button class="sjd-icobtn sjd-arch" title="Архив"><i class="fa-solid fa-layer-group"></i></button>
                <button class="sjd-icobtn sjd-set" title="Настройки"><i class="fa-solid fa-sliders"></i></button>
                <button class="sjd-icobtn sjd-close" title="Закрыть"><i class="fa-solid fa-xmark"></i></button></div>
            <div class="sjd-magazine">
                <div class="sjd-pages"></div>
                <div class="sjd-corner" title="Перелистнуть"></div>
                <div class="sjd-nav"><button class="sjd-prev"><i class="fa-solid fa-chevron-left"></i></button>
                    <div class="sjd-dots"></div><span class="sjd-pagenum">1/1</span>
                    <button class="sjd-next"><i class="fa-solid fa-chevron-right"></i></button></div>
                <div class="sjd-toast"></div>
                <div class="sjd-panel sjd-archive" hidden></div>
                <div class="sjd-panel sjd-settings" hidden>
                    <div class="sjd-srow"><label>Структура</label><select class="sjd-c-struct"><option value="mixed">Вперемешку</option><option value="solo">Целый номер про одного</option></select></div>
                    <div class="sjd-srow"><label>Про кого</label><select class="sjd-c-decider"><option value="ai">ИИ решает (поровну)</option><option value="alt">Чередовать</option><option value="rand">Случайно</option><option value="char">Только персонаж</option><option value="user">Только юзер</option></select></div>
                    <div class="sjd-srow"><label>Знак (персонажа)</label><select class="sjd-c-sign">${signOpts}</select></div>
                    <div class="sjd-srow"><label>Тон</label><select class="sjd-c-tone"><option value="tabloid">Таблоид</option><option value="spicy">Максимально едкий</option><option value="glamour">Глянец</option><option value="vanilla">Ванильный</option></select></div>
                    <div class="sjd-srow"><label>Обложка</label><select class="sjd-c-cover"><option value="avatar">Аватар</option><option value="meme">Мем</option></select></div>
                    <div class="sjd-srow"><label>Автовыпуск, сообщ.</label><input type="number" class="sjd-c-auto" min="0" max="100" value="0"></div>
                    <div class="sjd-shint">«Вперемешку» = в номере и персонаж, и юзер · «Про кого» рулит выбором · 0 = только по кнопке</div>
                </div>
            </div></div>`;
        document.body.appendChild(overlayEl);

        pagesEl = overlayEl.querySelector('.sjd-pages');
