    const hidePanels = () => overlayEl.querySelectorAll('.sjd-panel').forEach(p => p.setAttribute('hidden', ''));
    const closeMag = () => { overlayEl.classList.remove('sjd-on'); hidePanels(); };

    function openArchive() {
        overlayEl.querySelector('.sjd-settings').setAttribute('hidden', '');
        const el = overlayEl.querySelector('.sjd-archive');
        el.innerHTML = issues.length
            ? issues.map((it, idx) => `<div class="sjd-arow${idx === viewIndex ? ' on' : ''}" data-issue="${idx}"><b>№${it.num}</b> · ${dShort(it.date)} <span>${esc((it.data.headlines && it.data.headlines[0]) || 'выпуск')}</span></div>`).join('')
            : '<div class="sjd-body" style="text-align:center;padding:8px">Архив пуст</div>';
        el.toggleAttribute('hidden');
    }
    function openSettings() {
        overlayEl.querySelector('.sjd-archive').setAttribute('hidden', '');
        const cfg = loadCfg();
        overlayEl.querySelector('.sjd-c-struct').value = cfg.struct || 'mixed';
        overlayEl.querySelector('.sjd-c-decider').value = cfg.decider || 'ai';
        overlayEl.querySelector('.sjd-c-sign').value = loadSign();
        overlayEl.querySelector('.sjd-c-tone').value = cfg.tone;
        overlayEl.querySelector('.sjd-c-cover').value = cfg.cover || 'avatar';
        overlayEl.querySelector('.sjd-c-auto').value = cfg.autoN;
        overlayEl.querySelector('.sjd-settings').toggleAttribute('hidden');
