        overlayEl.querySelector('.sjd-arch').onclick = openArchive;
        overlayEl.querySelector('.sjd-set').onclick = openSettings;
        overlayEl.onclick = (e) => { if (e.target === overlayEl) closeMag(); };

        overlayEl.querySelector('.sjd-c-struct').addEventListener('change', (e) => { const c = loadCfg(); c.struct = e.target.value; saveCfg(c); });
        overlayEl.querySelector('.sjd-c-decider').addEventListener('change', (e) => { const c = loadCfg(); c.decider = e.target.value; saveCfg(c); });
        overlayEl.querySelector('.sjd-c-sign').addEventListener('change', (e) => { saveSign(e.target.value); render(); });
        overlayEl.querySelector('.sjd-c-tone').addEventListener('change', (e) => { const c = loadCfg(); c.tone = e.target.value; saveCfg(c); });
        overlayEl.querySelector('.sjd-c-cover').addEventListener('change', (e) => { const c = loadCfg(); c.cover = e.target.value; saveCfg(c); render(); });
        overlayEl.querySelector('.sjd-c-auto').addEventListener('change', (e) => { const c = loadCfg(); c.autoN = Math.max(0, Math.min(100, parseInt(e.target.value) || 0)); saveCfg(c); autoCounter = 0; });

        overlayEl.querySelector('.sjd-archive').addEventListener('click', (e) => {
            const row = e.target.closest('[data-issue]'); if (!row) return;
            viewIndex = parseInt(row.dataset.issue) || 0;
            hidePanels(); render();
        });

        pagesEl.addEventListener('click', (e) => {
            if (e.target.closest('[data-new]')) { newIssue(false); return; }
            const goto = e.target.closest('[data-goto]'); if (goto) { goPage(parseInt(goto.dataset.goto) || 0); return; }
            const giftCover = e.target.closest('.sjd-gift .cover2'); if (giftCover) { if (giftCover.classList.contains('locked')) { toast('в этом номере эффект уже выбран'); } else { const gw = giftCover.closest('[data-gift]'); gw?.classList.add('open'); applyEffect('gift', gw?.dataset.subj); } return; }
            if (e.target.closest('[data-comic]')) { armComic(); return; }
            const apply = e.target.closest('[data-apply]'); if (apply) { applyEffect(apply.dataset.apply, apply.dataset.subj); return; }
        });

        document.addEventListener('keydown', (e) => {
            if (!overlayEl.classList.contains('sjd-on')) return;
            if (e.key === 'ArrowRight') flip(1); else if (e.key === 'ArrowLeft') flip(-1);
            else if (e.key === 'Escape') closeMag();
        });

        const mag = overlayEl.querySelector('.sjd-magazine'); let sx = 0, sActive = false;
        mag.addEventListener('pointerdown', (e) => { if (e.target.closest('.sjd-btn,.cover2,.sjd-nav,button,.sjd-icobtn,.sjd-panel')) return; sx = e.clientX; sActive = true; });
        mag.addEventListener('pointerup', (e) => { if (!sActive) return; sActive = false; const dx = e.clientX - sx; if (dx < -45) flip(1); else if (dx > 45) flip(-1); });

        let pDrag = false, moved = false, ox = 0, oy = 0, startX = 0, startY = 0;
        fabEl.addEventListener('pointerdown', (e) => { pDrag = true; moved = false; fabEl.setPointerCapture(e.pointerId); const r = fabEl.getBoundingClientRect(); ox = e.clientX - r.left; oy = e.clientY - r.top; startX = e.clientX; startY = e.clientY; });
        fabEl.addEventListener('pointermove', (e) => { if (!pDrag) return; if (Math.abs(e.clientX - startX) + Math.abs(e.clientY - startY) > 10) moved = true; fabEl.style.left = (e.clientX - ox) + 'px'; fabEl.style.top = (e.clientY - oy) + 'px'; fabEl.style.right = 'auto'; fabEl.style.bottom = 'auto'; });
        fabEl.addEventListener('pointerup', () => { pDrag = false; if (!moved) { viewIndex = 0; refresh(); overlayEl.classList.add('sjd-on'); } });
    }

    // ---------- init ----------
    buildUI();
    try {
        ctx.eventSource.on(ctx.event_types.CHAT_CHANGED, () => { viewIndex = 0; autoCounter = 0; refresh(); });
        ctx.eventSource.on(ctx.event_types.MESSAGE_RECEIVED, () => {
            clearOneShots();
            const cfg = loadCfg();
            if (cfg.autoN > 0 && !busy) { autoCounter++; if (autoCounter >= cfg.autoN) { autoCounter = 0; newIssue(true); } }
        });
    } catch (e) { console.error('[SJD] events', e); }
    window.SJD = { ready: true, refresh, injectCSS };
    refresh();
}
